    <div class="zr-head"><b>天星择日</b> · toạ <span class="zh">${i.sitting}</span> ${dh[i.sitting]} · hướng <span class="zh">${i.facing}</span> ${dh[i.facing]} · sơn ${i.mountainElementLabel} (${i.mountainSystem==="zhengti"?"正体":"化气"})</div>
